// ── Inline coupon email renderer ──────────────────────────────────────────────
function buildCouponEmail(v: Record<string, string>): string {
  const e = (s: string) => s.replace(/</g, '&lt;').replace(/>/g, '&gt;');
  const code = e(v.couponCode ?? '');
  const name = e(v.recipientName ?? 'Cliente');
  const discount = e(v.discountText ?? '');
  const couponName = e(v.couponName ?? '');
  const description = v.description ? `<p style="font-size:13px;color:#718096;margin-top:4px;">${e(v.description)}</p>` : '';
  const expiryRow = v.expiresAt ? `<p style="font-size:12px;color:#718096;margin-top:8px;">⏳ Válido hasta: <strong>${e(v.expiresAt)}</strong></p>` : '';
  const minRow = v.minimumAmount ? `<p style="font-size:12px;color:#718096;margin-top:4px;">Monto mínimo: <strong>${e(v.minimumAmount)}</strong></p>` : '';
  const qrBlock = v.qrUrl ? `<div style="text-align:center;margin-top:20px;"><img src="${v.qrUrl}" width="110" height="110" alt="QR ${code}" style="border-radius:8px;border:1.5px solid #ffd4b3;"/><p style="font-size:10px;color:#a0aec0;margin-top:5px;letter-spacing:1px;text-transform:uppercase;">Escanear</p></div>` : '';
  const year = v.currentYear ?? new Date().getFullYear();

  return `<!DOCTYPE html><html lang="es"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Tu cupón - Piums</title></head>
<body style="margin:0;padding:0;background:#f5f5f5;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,Arial,sans-serif;">
<div style="max-width:600px;margin:40px auto;background:#fff;border-radius:16px;overflow:hidden;box-shadow:0 4px 24px rgba(0,0,0,.10);">
  <!-- Header -->
  <div style="background:linear-gradient(135deg,#FF6A00,#e05e00);padding:36px 30px 32px;text-align:center;color:#fff;">
    <div style="margin-bottom:16px;"><img src="data:image/png;base64," width="80" height="80" alt="Piums" style="border-radius:50%;background:rgba(255,255,255,0.15);padding:8px;" /></div>
    <h1 style="font-size:26px;font-weight:700;margin:0 0 8px;">¡Tienes un cupón de descuento!</h1>
    <p style="font-size:15px;opacity:.92;margin:0;">Úsalo en tu próxima reserva en Piums</p>
  </div>
  <!-- Body -->
  <div style="padding:40px 32px;">
    <p style="font-size:17px;color:#2d3748;margin-bottom:20px;">Hola <strong>${name}</strong>,</p>
    <p style="font-size:15px;color:#4a5568;margin-bottom:24px;">Te compartimos este cupón exclusivo con <strong>${discount}</strong> de descuento. Aplícalo al momento de reservar.</p>
    <!-- Coupon card -->
    <div style="border:2.5px dashed #FF6A00;border-radius:14px;overflow:hidden;background:#fff8f4;margin-bottom:28px;">
      <div style="padding:28px;text-align:center;">
        <div style="display:inline-block;background:linear-gradient(135deg,#FF6A00,#e05e00);color:#fff;font-size:36px;font-weight:800;padding:10px 28px;border-radius:10px;letter-spacing:-1px;box-shadow:0 4px 14px rgba(255,106,0,.30);margin-bottom:12px;">${discount}</div>
        <p style="font-size:16px;font-weight:600;color:#2d3748;">${couponName}</p>
        ${description}
      </div>
      <div style="border-top:2px dashed #ffd4b3;margin:0 16px;"></div>
      <div style="padding:20px 28px;display:flex;align-items:center;justify-content:space-between;gap:20px;">
        <div>
          <p style="font-size:11px;font-weight:600;text-transform:uppercase;letter-spacing:1px;color:#a0aec0;margin-bottom:6px;">Tu código</p>
          <div style="font-family:'Courier New',monospace;font-size:24px;font-weight:700;letter-spacing:3px;color:#FF6A00;background:#fff;border:1.5px solid #ffd4b3;border-radius:8px;padding:8px 14px;display:inline-block;">${code}</div>
          ${expiryRow}${minRow}
        </div>
        ${qrBlock}
      </div>
    </div>
    <!-- Steps -->
    <div style="background:#f7fafc;border-radius:10px;padding:22px 24px;margin-bottom:28px;">
      <p style="font-size:13px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;color:#2d3748;margin-bottom:14px;">¿Cómo usarlo?</p>
      <div style="display:flex;gap:12px;margin-bottom:10px;"><div style="min-width:24px;height:24px;background:#FF6A00;color:#fff;border-radius:50%;font-size:12px;font-weight:700;text-align:center;line-height:24px;">1</div><p style="font-size:13px;color:#4a5568;padding-top:3px;">Ingresa a <strong>piums.io</strong> y elige el artista y servicio que deseas reservar.</p></div>
      <div style="display:flex;gap:12px;margin-bottom:10px;"><div style="min-width:24px;height:24px;background:#FF6A00;color:#fff;border-radius:50%;font-size:12px;font-weight:700;text-align:center;line-height:24px;">2</div><p style="font-size:13px;color:#4a5568;padding-top:3px;">En el paso de revisión, busca <strong>"¿Tienes un código?"</strong> e ingresa tu código.</p></div>
      <div style="display:flex;gap:12px;"><div style="min-width:24px;height:24px;background:#FF6A00;color:#fff;border-radius:50%;font-size:12px;font-weight:700;text-align:center;line-height:24px;">3</div><p style="font-size:13px;color:#4a5568;padding-top:3px;">El descuento se aplicará automáticamente al total de tu reserva.</p></div>
    </div>
    <div style="text-align:center;">
      <a href="https://piums.io/artists" style="display:inline-block;padding:14px 36px;background:linear-gradient(135deg,#FF6A00,#e05e00);color:#fff;text-decoration:none;border-radius:10px;font-weight:700;font-size:15px;">Explorar artistas →</a>
    </div>
  </div>
  <!-- Footer -->
  <div style="background:#f7fafc;padding:28px 32px;text-align:center;border-top:1px solid #e2e8f0;">
    <p style="font-size:13px;color:#718096;margin-bottom:6px;"><strong>Piums</strong> — Conectando talento con clientes</p>
    <p style="font-size:12px;color:#a0aec0;">© ${year} Piums. Todos los derechos reservados.</p>
  </div>
</div>
</body></html>`;
}

// ============================================================================
// Admin CRUD
// ============================================================================

export const adminListCoupons = async (req: Request, res: Response, next: NextFunction) => {
  try {
    if ((req as any).user?.role !== 'admin') {
      return next(new AppError(403, 'Acceso denegado. Se requiere rol de administrador.'));
    }
    const { status, targetType, page, limit } = req.query;
    const result = await couponService.getCoupons({
      status: status as string | undefined,
      targetType: targetType as string | undefined,
      page: page ? parseInt(page as string, 10) : 1,
      limit: limit ? parseInt(limit as string, 10) : 20,
    });
    res.json(result);
  } catch (error) {
    next(error);
  }
};

