// ============================================================================
// Bulk generate
// ============================================================================

export const adminBulkGenerate = async (req: Request, res: Response, next: NextFunction) => {
  try {
    if ((req as any).user?.role !== 'admin') {
      return next(new AppError(403, 'Acceso denegado. Se requiere rol de administrador.'));
    }
    const adminId = (req as any).user!.id;
    const { prefix, count, template } = req.body as {
      prefix: string;
      count: number;
      template: any;
    };
    if (!prefix || !count || !template) {
      return next(new AppError(400, 'prefix, count y template son requeridos'));
    }
    const coupons = await couponService.bulkGenerateCoupons(template, count, prefix, adminId);
    res.status(201).json({ ok: true, count: coupons.length, coupons });
  } catch (error) {
    next(error);
  }
};

// ============================================================================
// Send coupon by email
// ============================================================================

export const adminSendCouponEmail = async (req: Request, res: Response, next: NextFunction) => {
  try {
    if ((req as any).user?.role !== 'admin') {
      return next(new AppError(403, 'Acceso denegado. Se requiere rol de administrador.'));
    }

    const coupon = await couponService.getCouponById(req.params['id'] as string);
    const { email, recipientName } = req.body as { email: string; recipientName?: string };

    if (!email) {
      return next(new AppError(400, 'El campo email es requerido'));
    }

    const name = recipientName || 'Cliente';
    const qrUrl = `https://api.qrserver.com/v1/create-qr-code/?size=200x200&data=${encodeURIComponent(coupon.code)}`;

    let discountText = '';
    if (coupon.discountType === 'PERCENTAGE') {
      discountText = `${coupon.discountValue}%`;
    } else {
      discountText = `$${(coupon.discountValue / 100).toFixed(2)} ${coupon.currency}`;
    }

    const expiresAtText = coupon.expiresAt
      ? new Date(coupon.expiresAt).toLocaleDateString('es-GT', { year: 'numeric', month: 'long', day: 'numeric' })
      : '';

    const minimumAmountText = coupon.minimumAmount
      ? `$${(coupon.minimumAmount / 100).toFixed(2)} ${coupon.currency}`
      : '';

    const currentYear = new Date().getFullYear();

    // Build email HTML (inline rendering)
    const emailHtml = buildCouponEmail({
      recipientName: name,
      couponCode: coupon.code,
      couponName: coupon.name,
      description: coupon.description || '',
      discountText,
      expiresAt: expiresAtText,
      minimumAmount: minimumAmountText,
      qrUrl,
      currentYear: String(currentYear),
    });

    await notificationsClient.sendNotification({
      userId: '00000000-0000-0000-0000-000000000000',
      type: 'COUPON_SENT',
      channel: 'EMAIL',
      emailTo: email,
      emailSubject: `🎟️ Tu cupón ${coupon.code} — ${discountText} de descuento en Piums`,
      emailHtml,
      title: `Tu cupón de descuento: ${coupon.code}`,
      message: `Hola ${name}, tienes un cupón ${coupon.code} con ${discountText} de descuento.`,
    });

    logger.info('Email de cupón enviado', 'COUPON_CONTROLLER', { couponId: coupon.id, email });
    res.json({ ok: true });
  } catch (error) {
    next(error);
  }
};

// ============================================================================
// Public / user routes
// ============================================================================

export const validateCoupon = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const { code, userId, bookingId, bookingTotal, artistId, serviceId } = req.body as {
      code: string;
      userId: string;
      bookingId: string;
      bookingTotal: number;
      artistId?: string;
      serviceId?: string;
    };

    if (!code || !userId || !bookingId || bookingTotal === undefined) {
      return next(new AppError(400, 'code, userId, bookingId y bookingTotal son requeridos'));
    }

    const result = await couponService.validateCoupon(code, userId, bookingId, bookingTotal, artistId, serviceId);
    res.json(result);
  } catch (error) {
    next(error);
  }
};

export const redeemCouponInternal = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const { couponId, userId, bookingId, discountApplied } = req.body as {
      couponId: string;
      userId: string;
      bookingId: string;
      discountApplied: number;
    };

    if (!couponId || !userId || !bookingId || discountApplied === undefined) {
      return next(new AppError(400, 'couponId, userId, bookingId y discountApplied son requeridos'));
    }

    const use = await couponService.redeemCoupon(couponId, userId, bookingId, discountApplied);
    res.json({ ok: true, use });
  } catch (error) {
    next(error);
  }
};

